{action_set_definitions}: {
  "get_application_state": {
    "description": "Retrieves the full current state of a specific zoning variance application, including the document vault, checklist, and metadata.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique identifier for the variance request (e.g., 'VAR-2024-SIG-042')."
        }
      },
      "required": [
        "application_id"
      ]
    },
    "example_output": {
      "application_id": "VAR-2024-SIG-042",
      "document_vault": [
        {
          "id": "D-SIG-001",
          "name": "Site Plan",
          "status": "Verified"
        },
        {
          "id": "D-SIG-002",
          "name": "Luminance Specs",
          "status": "Missing"
        }
      ],
      "internal_compliance_checklist": {
        "neighbor_notification_sent": false,
        "fee_processed": true
      }
    }
  },
  "get_signage_reference_guide": {
    "description": "Retrieves the official regulatory requirements for signage, including EMC luminance, dwell time, and Historic Overlay District constraints.",
    "parameters": {
      "type": "object",
      "properties": {
        "category": {
          "type": "string",
          "enum": [
            "EMC_Standards",
            "Historic_Overlay",
            "General_Signage"
          ],
          "description": "The specific section of the reference guide to retrieve."
        }
      },
      "required": [
        "category"
      ]
    },
    "example_output": {
      "max_luminance_nits": 5000,
      "min_dwell_time_seconds": 8,
      "overlay_rules": "No flashing; compatible materials."
    }
  },
  "verify_document_details": {
    "description": "Extracts specific technical data (e.g., luminance, dwell time) from a document in the vault.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "document_id": {
          "type": "string",
          "description": "The ID of the document to inspect."
        }
      },
      "required": [
        "application_id",
        "document_id"
      ]
    },
    "example_output": {
      "extracted_luminance": 4800,
      "extracted_dwell_time": 10
    }
  },
  "update_checklist_status": {
    "description": "Updates the boolean status of a specific internal compliance checklist item.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "item_key": {
          "type": "string",
          "description": "The exact key name from the internal_compliance_checklist (e.g., 'neighbor_notification_sent')."
        },
        "status": {
          "type": "boolean",
          "description": "The updated status (true for satisfied/verified)."
        }
      },
      "required": [
        "application_id",
        "item_key",
        "status"
      ]
    },
    "example_output": {
      "updated_key": "neighbor_notification_sent",
      "new_status": true
    }
  },
  "sanitize_application_record": {
    "description": "Filters the justification text to remove content-based speech or arguments, ensuring First Amendment compliance.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "raw_text": {
          "type": "string",
          "description": "The original justification text from the application."
        }
      },
      "required": [
        "application_id",
        "raw_text"
      ]
    },
    "example_output": {
      "sanitized_text": "Requested variance is based on site visibility and physical property orientation."
    }
  },
  "advance_to_final_recommendation": {
    "description": "Submits the final review report and moves the application to the 'Final Recommendation' workflow stage.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "report_summary": {
          "type": "string",
          "description": "Detailed report addressing EMC specs, site constraints, missing documents, and compliance."
        }
      },
      "required": [
        "application_id",
        "report_summary"
      ]
    },
    "example_output": {
      "new_status": "Final Recommendation",
      "timestamp": "2024-05-20T10:00:00Z"
    }
  }
}
